import{_ as e,c as a,o,ag as i}from"./chunks/framework.Cycwnjj0.js";const c=JSON.parse('{"title":"Supported Formats","description":"","frontmatter":{},"headers":[],"relativePath":"reference/formats/index.md","filePath":"reference/formats/index.md","lastUpdated":null}'),r={name:"reference/formats/index.md"};function s(l,t,n,d,p,g){return o(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="supported-formats" tabindex="-1">Supported Formats <a class="header-anchor" href="#supported-formats" aria-label="Permalink to &quot;Supported Formats&quot;">​</a></h1><p>OxiDex supports 140+ file format families with comprehensive metadata extraction and writing capabilities.</p><p><strong>Legend:</strong></p><ul><li>✅ <strong>Fully Implemented</strong> - Read and write support with comprehensive tag coverage</li><li>🔄 <strong>Partial Support</strong> - Read support implemented, write support limited</li><li>⏳ <strong>Planned</strong> - On the roadmap for future implementation</li></ul><h2 id="image-formats" tabindex="-1">Image Formats <a class="header-anchor" href="#image-formats" aria-label="Permalink to &quot;Image Formats&quot;">​</a></h2><h3 id="jpeg-joint-photographic-experts-group" tabindex="-1">JPEG (Joint Photographic Experts Group) <a class="header-anchor" href="#jpeg-joint-photographic-experts-group" aria-label="Permalink to &quot;JPEG (Joint Photographic Experts Group)&quot;">​</a></h3><p><strong>Status:</strong> ✅ Fully Implemented</p><p><strong>File Extensions:</strong> <code>.jpg</code>, <code>.jpeg</code>, <code>.jpe</code></p><p><strong>Metadata Types:</strong></p><ul><li>✅ EXIF (Exchangeable Image File Format)</li><li>✅ XMP (Extensible Metadata Platform)</li><li>✅ IPTC (International Press Telecommunications Council)</li><li>✅ JFIF (JPEG File Interchange Format)</li><li>✅ GPS (Geolocation data)</li><li>✅ ICC Profile (Color management)</li><li>✅ Photoshop metadata</li><li>✅ Thumbnail extraction</li></ul><p><strong>Available Tags:</strong> 244 EXIF tags + 122 IPTC tags + XMP support</p><p><strong>Common Use Cases:</strong></p><ul><li>Digital camera photos</li><li>Web images</li><li>Social media uploads</li><li>Scanned documents</li></ul><h3 id="tiff-tagged-image-file-format" tabindex="-1">TIFF (Tagged Image File Format) <a class="header-anchor" href="#tiff-tagged-image-file-format" aria-label="Permalink to &quot;TIFF (Tagged Image File Format)&quot;">​</a></h3><p><strong>Status:</strong> ✅ Fully Implemented</p><p><strong>File Extensions:</strong> <code>.tif</code>, <code>.tiff</code></p><p><strong>Metadata Types:</strong></p><ul><li>✅ EXIF</li><li>✅ XMP</li><li>✅ IPTC</li><li>✅ GPS</li><li>✅ ICC Profile</li><li>✅ Photoshop</li><li>✅ Multi-page/multi-image support</li></ul><p><strong>Available Tags:</strong> 244 EXIF tags + TIFF-specific tags</p><p><strong>Common Use Cases:</strong></p><ul><li>Professional photography</li><li>Archival images</li><li>Scientific imaging</li><li>Medical imaging (DICOM-TIFF)</li></ul><h3 id="png-portable-network-graphics" tabindex="-1">PNG (Portable Network Graphics) <a class="header-anchor" href="#png-portable-network-graphics" aria-label="Permalink to &quot;PNG (Portable Network Graphics)&quot;">​</a></h3><p><strong>Status:</strong> ✅ Fully Implemented</p><p><strong>File Extensions:</strong> <code>.png</code></p><p><strong>Metadata Types:</strong></p><ul><li>✅ PNG text chunks (tEXt, zTXt, iTXt)</li><li>✅ XMP</li><li>✅ EXIF (embedded via PNG chunks)</li><li>✅ ICC Profile</li><li>✅ Creation time (tIME chunk)</li><li>✅ Physical dimensions (pHYs chunk)</li></ul><p><strong>Available Tags:</strong> 30 PNG-specific tags + EXIF/XMP support</p><p><strong>Common Use Cases:</strong></p><ul><li>Web graphics</li><li>Screenshots</li><li>Lossless image archiving</li><li>Images with transparency</li></ul><h3 id="raw-camera-formats" tabindex="-1">RAW Camera Formats <a class="header-anchor" href="#raw-camera-formats" aria-label="Permalink to &quot;RAW Camera Formats&quot;">​</a></h3><p><strong>Status:</strong> ✅ Fully Implemented (40+ formats)</p><p><strong>Supported Formats:</strong></p><ul><li><strong>Canon:</strong> CR2, CR3, CRW</li><li><strong>Nikon:</strong> NEF, NRW</li><li><strong>Sony:</strong> ARW, SR2, SRF, SRW, ARQ, ARI</li><li><strong>Fujifilm:</strong> RAF</li><li><strong>Olympus:</strong> ORF, ORI</li><li><strong>Pentax:</strong> PEF</li><li><strong>Panasonic:</strong> RW2, RWL</li><li><strong>Hasselblad:</strong> 3FR, FFF</li><li><strong>Phase One:</strong> IIQ</li><li><strong>Mamiya:</strong> MEF</li><li><strong>Leaf:</strong> MOS</li><li><strong>Kodak:</strong> DCR, KDC</li><li><strong>Minolta:</strong> MDC, MRW</li><li><strong>Epson:</strong> ERF</li><li><strong>Sigma:</strong> X3F</li><li><strong>GoPro:</strong> GPR</li><li><strong>Adobe:</strong> DNG (Digital Negative)</li><li><strong>HEIF:</strong> HIF</li><li><strong>Light:</strong> LRI</li><li><strong>Sinar:</strong> STI</li><li><strong>Generic:</strong> RAW, CAM, REV</li></ul><p><strong>Metadata Support:</strong> EXIF, XMP, maker notes for each manufacturer</p><h2 id="video-formats" tabindex="-1">Video Formats <a class="header-anchor" href="#video-formats" aria-label="Permalink to &quot;Video Formats&quot;">​</a></h2><h3 id="mp4-quicktime" tabindex="-1">MP4/QuickTime <a class="header-anchor" href="#mp4-quicktime" aria-label="Permalink to &quot;MP4/QuickTime&quot;">​</a></h3><p><strong>Status:</strong> ✅ Fully Implemented</p><p><strong>File Extensions:</strong> <code>.mp4</code>, <code>.m4v</code>, <code>.mov</code>, <code>.3gp</code>, <code>.3g2</code></p><p><strong>Metadata Types:</strong></p><ul><li>✅ QuickTime atoms (moov, udta, meta)</li><li>✅ Creation/modification times</li><li>✅ Duration, dimensions</li><li>✅ GPS coordinates</li><li>✅ Camera make/model</li><li>✅ XMP packets</li></ul><p><strong>Available Tags:</strong> 143 QuickTime-specific tags</p><p><strong>Common Use Cases:</strong></p><ul><li>Video library management</li><li>Smartphone video metadata</li><li>Media asset databases</li><li>GPS-tagged videos</li></ul><h3 id="additional-video-formats" tabindex="-1">Additional Video Formats <a class="header-anchor" href="#additional-video-formats" aria-label="Permalink to &quot;Additional Video Formats&quot;">​</a></h3><p><strong>Status:</strong> ✅ Phase 1 Complete</p><ul><li><strong>MKV/WebM</strong> (Matroska) - ✅ Complete</li><li><strong>FLV</strong> (Flash Video) - ✅ Complete</li><li><strong>AVI</strong> (Audio Video Interleave) - ✅ Complete</li><li><strong>MTS/M2TS</strong> (AVCHD) - ✅ Complete</li></ul><h2 id="audio-formats" tabindex="-1">Audio Formats <a class="header-anchor" href="#audio-formats" aria-label="Permalink to &quot;Audio Formats&quot;">​</a></h2><p><strong>Status:</strong> ✅ Phase 1 Complete</p><ul><li><strong>MP3</strong> (ID3 tags) - ✅ Complete</li><li><strong>FLAC</strong> (Free Lossless Audio Codec) - ✅ Complete</li><li><strong>AAC</strong> (Advanced Audio Coding) - ✅ Complete</li><li><strong>WAV</strong> (Waveform Audio) - ✅ Complete</li><li><strong>OGG Vorbis</strong> - ✅ Complete</li><li><strong>Opus</strong> - ✅ Complete</li><li><strong>APE</strong> (Monkey&#39;s Audio) - ✅ Complete</li></ul><h2 id="document-formats" tabindex="-1">Document Formats <a class="header-anchor" href="#document-formats" aria-label="Permalink to &quot;Document Formats&quot;">​</a></h2><h3 id="pdf-portable-document-format" tabindex="-1">PDF (Portable Document Format) <a class="header-anchor" href="#pdf-portable-document-format" aria-label="Permalink to &quot;PDF (Portable Document Format)&quot;">​</a></h3><p><strong>Status:</strong> ✅ Fully Implemented</p><p><strong>File Extensions:</strong> <code>.pdf</code></p><p><strong>Metadata Types:</strong></p><ul><li>✅ PDF Info Dictionary (Title, Author, Subject, Keywords)</li><li>✅ Creation/Modification dates</li><li>✅ XMP metadata packets</li><li>✅ ICC profiles</li></ul><p><strong>Common Use Cases:</strong></p><ul><li>Document metadata extraction</li><li>PDF library management</li><li>Compliance and archiving</li></ul><h3 id="pe-portable-executable" tabindex="-1">PE (Portable Executable) <a class="header-anchor" href="#pe-portable-executable" aria-label="Permalink to &quot;PE (Portable Executable)&quot;">​</a></h3><p><strong>Status:</strong> ✅ Fully Implemented</p><p><strong>File Extensions:</strong> <code>.exe</code>, <code>.dll</code>, <code>.sys</code></p><p><strong>Metadata Types:</strong></p><ul><li>✅ Version information</li><li>✅ File properties</li><li>✅ Digital signatures</li><li>✅ Resource metadata</li></ul><p><strong>Common Use Cases:</strong></p><ul><li>Windows executable analysis</li><li>Software inventory</li><li>Security auditing</li></ul><h2 id="metadata-standards" tabindex="-1">Metadata Standards <a class="header-anchor" href="#metadata-standards" aria-label="Permalink to &quot;Metadata Standards&quot;">​</a></h2><h3 id="exif-exchangeable-image-file-format" tabindex="-1">EXIF (Exchangeable Image File Format) <a class="header-anchor" href="#exif-exchangeable-image-file-format" aria-label="Permalink to &quot;EXIF (Exchangeable Image File Format)&quot;">​</a></h3><p><strong>Status:</strong> ✅ Comprehensive Support</p><p><strong>Supported in Formats:</strong> JPEG, TIFF, PNG, RAW formats</p><p><strong>Tag Categories:</strong></p><ul><li>Image structure (width, height, color space)</li><li>Camera settings (ISO, aperture, shutter speed, focal length)</li><li>Camera identification (make, model, serial number)</li><li>Date/time stamps (original, digitized, modified)</li><li>Image processing (white balance, exposure compensation, flash)</li><li>Thumbnail images</li><li>Copyright and author information</li></ul><p><strong>Available Tags:</strong> 718 tags from EXIF specification</p><p><strong>Standards Compliance:</strong> EXIF 2.3 specification</p><h3 id="xmp-extensible-metadata-platform" tabindex="-1">XMP (Extensible Metadata Platform) <a class="header-anchor" href="#xmp-extensible-metadata-platform" aria-label="Permalink to &quot;XMP (Extensible Metadata Platform)&quot;">​</a></h3><p><strong>Status:</strong> ✅ Fully Implemented</p><p><strong>Supported in Formats:</strong> JPEG, TIFF, PNG, PDF, MP4</p><p><strong>XMP Namespaces:</strong></p><ul><li><code>dc</code> (Dublin Core) - Title, Creator, Rights, Description</li><li><code>xmp</code> - Base XMP properties</li><li><code>xmpRights</code> - Copyright management</li><li><code>photoshop</code> - Adobe Photoshop metadata</li><li><code>exif</code> - EXIF properties in XMP format</li><li><code>tiff</code> - TIFF properties in XMP format</li><li><code>aux</code> - Additional camera metadata</li><li><code>iptcCore</code> - IPTC Core metadata</li><li><code>iptcExt</code> - IPTC Extension metadata</li><li><code>plus</code> - Picture Licensing Universal System</li></ul><p><strong>Read Operations:</strong> ✅ Full XML parsing <strong>Write Operations:</strong> ✅ Full XML serialization</p><h3 id="iptc-international-press-telecommunications-council" tabindex="-1">IPTC (International Press Telecommunications Council) <a class="header-anchor" href="#iptc-international-press-telecommunications-council" aria-label="Permalink to &quot;IPTC (International Press Telecommunications Council)&quot;">​</a></h3><p><strong>Status:</strong> ✅ Fully Implemented</p><p><strong>Supported in Formats:</strong> JPEG, TIFF</p><p><strong>IPTC Categories:</strong></p><ul><li>Descriptive metadata (Caption, Keywords, Headline)</li><li>Administrative metadata (Credit, Source, Copyright Notice)</li><li>People and locations (City, Province, Country, Creator)</li><li>Rights information (Usage Terms, Copyright Notice)</li><li>Technical metadata (Date Created, Digital Creation Date)</li></ul><p><strong>Available Tags:</strong> 122 IPTC tags</p><p><strong>Standards Compliance:</strong> IPTC Core 1.3, IPTC Extension</p><h3 id="gps-metadata" tabindex="-1">GPS Metadata <a class="header-anchor" href="#gps-metadata" aria-label="Permalink to &quot;GPS Metadata&quot;">​</a></h3><p><strong>Status:</strong> ✅ Fully Implemented</p><p><strong>Supported in Formats:</strong> JPEG, TIFF, MP4/MOV, RAW</p><p><strong>GPS Tags:</strong></p><ul><li>Latitude, Longitude (decimal degrees)</li><li>Altitude (meters above sea level)</li><li>Timestamp (UTC)</li><li>Speed, Track (direction of movement)</li><li>Satellites used, DOP (dilution of precision)</li><li>Map Datum (coordinate system)</li><li>Differential correction</li></ul><p><strong>Available Tags:</strong> 32 GPS-specific tags</p><p><strong>Coordinate Formats:</strong> Decimal degrees, degrees/minutes/seconds (DMS)</p><h2 id="additional-metadata" tabindex="-1">Additional Metadata <a class="header-anchor" href="#additional-metadata" aria-label="Permalink to &quot;Additional Metadata&quot;">​</a></h2><h3 id="icc-profile-color-management" tabindex="-1">ICC Profile (Color Management) <a class="header-anchor" href="#icc-profile-color-management" aria-label="Permalink to &quot;ICC Profile (Color Management)&quot;">​</a></h3><p><strong>Status:</strong> ✅ Fully Implemented</p><p><strong>Supported in Formats:</strong> JPEG, TIFF, PNG, PDF</p><p><strong>Profile Information:</strong></p><ul><li>Profile description</li><li>Color space (RGB, CMYK, Lab)</li><li>Rendering intent</li><li>White point, primaries</li><li>Gamma/transfer curve</li></ul><p><strong>Available Tags:</strong> 90 ICC Profile tags</p><h3 id="photoshop-metadata" tabindex="-1">Photoshop Metadata <a class="header-anchor" href="#photoshop-metadata" aria-label="Permalink to &quot;Photoshop Metadata&quot;">​</a></h3><p><strong>Status:</strong> ✅ Fully Implemented</p><p><strong>Supported in Formats:</strong> JPEG, TIFF, PNG</p><p><strong>Photoshop Resources:</strong></p><ul><li>Image resources (layers, paths)</li><li>Copyright flag</li><li>URL</li><li>Credit, Source</li><li>Caption Writer</li></ul><p><strong>Available Tags:</strong> 136 Photoshop-specific tags</p><h3 id="maker-notes" tabindex="-1">Maker Notes <a class="header-anchor" href="#maker-notes" aria-label="Permalink to &quot;Maker Notes&quot;">​</a></h3><p><strong>Status:</strong> ✅ Comprehensive Support (30+ manufacturers)</p><p><strong>Canon MakerNotes:</strong> 930 tags</p><ul><li>Phase 1: Basic tags (ImageType, SerialNumber, ModelID)</li><li>Phase 2: Array tags (CameraSettings, ShotInfo, FocalLength)</li><li>Phase 3: Advanced (Lens database, AFInfo, FileInfo)</li></ul><p><strong>Nikon MakerNotes:</strong> 2,398 tags (main) + 3,512 tags (NikonCustom) <strong>Sony MakerNotes:</strong> 1,148 tags <strong>Pentax MakerNotes:</strong> 876 tags</p><h2 id="format-detection" tabindex="-1">Format Detection <a class="header-anchor" href="#format-detection" aria-label="Permalink to &quot;Format Detection&quot;">​</a></h2><p>OxiDex uses <strong>magic number detection</strong> to identify file formats:</p><ol><li>Reads the first few bytes (magic number)</li><li>Matches against known format signatures</li><li>Falls back to file extension if ambiguous</li></ol><p><strong>Format Signatures:</strong></p><table tabindex="0"><thead><tr><th>Format</th><th>Magic Bytes</th><th>Offset</th></tr></thead><tbody><tr><td>JPEG</td><td><code>FF D8 FF</code></td><td>0</td></tr><tr><td>PNG</td><td><code>89 50 4E 47 0D 0A 1A 0A</code></td><td>0</td></tr><tr><td>TIFF (LE)</td><td><code>49 49 2A 00</code></td><td>0</td></tr><tr><td>TIFF (BE)</td><td><code>4D 4D 00 2A</code></td><td>0</td></tr><tr><td>PDF</td><td><code>25 50 44 46</code> (<code>%PDF</code>)</td><td>0</td></tr><tr><td>MP4/MOV</td><td><code>66 74 79 70</code> (<code>ftyp</code>)</td><td>4</td></tr></tbody></table><p>This ensures robust format detection even with incorrect extensions.</p><h2 id="performance-by-format" tabindex="-1">Performance by Format <a class="header-anchor" href="#performance-by-format" aria-label="Permalink to &quot;Performance by Format&quot;">​</a></h2><p><strong>Relative Performance</strong> (compared to baseline JPEG parsing):</p><table tabindex="0"><thead><tr><th>Format</th><th>Read Speed</th><th>Write Speed</th><th>Notes</th></tr></thead><tbody><tr><td>JPEG</td><td>1.0x (baseline)</td><td>1.0x</td><td>Optimized segment parsing</td></tr><tr><td>TIFF</td><td>0.9x</td><td>0.9x</td><td>IFD chain traversal</td></tr><tr><td>PNG</td><td>1.1x</td><td>1.1x</td><td>Simple chunk-based format</td></tr><tr><td>PDF</td><td>0.8x</td><td>0.8x</td><td>Object parsing</td></tr><tr><td>MP4/MOV</td><td>0.7x</td><td>N/A</td><td>Atom tree traversal</td></tr></tbody></table><p>All formats process typical files in &lt; 50ms on modern hardware.</p><h2 id="tag-database-statistics" tabindex="-1">Tag Database Statistics <a class="header-anchor" href="#tag-database-statistics" aria-label="Permalink to &quot;Tag Database Statistics&quot;">​</a></h2><p><strong>Total Tags:</strong> 32,677 (113% of ExifTool&#39;s 28,853 tags)</p><p><strong>Tags by Format Family:</strong></p><ul><li>NikonCustom: 3,512 tags</li><li>DICOM: 3,149 tags</li><li>Nikon: 2,398 tags</li><li>Sony: 1,148 tags</li><li>QuickTime: 1,069 tags</li><li>Canon: 930 tags</li><li>Casio: 930 tags</li><li>Pentax: 876 tags</li><li>EXIF: 718 tags</li><li>And 131+ more format families</li></ul><h2 id="checking-format-support" tabindex="-1">Checking Format Support <a class="header-anchor" href="#checking-format-support" aria-label="Permalink to &quot;Checking Format Support&quot;">​</a></h2><p>Use the CLI to check format support:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">oxidex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> photo.jpg</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Supported formats will display metadata. Unsupported formats show:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Error: Unsupported file format: unknown</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="future-roadmap" tabindex="-1">Future Roadmap <a class="header-anchor" href="#future-roadmap" aria-label="Permalink to &quot;Future Roadmap&quot;">​</a></h2><p><strong>v1.1 (Current):</strong> 140+ format families with full read/write support ✅ <strong>v2.0 Goal:</strong> Enhanced maker notes support for all major camera vendors <strong>v3.0 Goal:</strong> Complete ExifTool tag parity (28,853+ tags)</p><h2 id="additional-resources" tabindex="-1">Additional Resources <a class="header-anchor" href="#additional-resources" aria-label="Permalink to &quot;Additional Resources&quot;">​</a></h2><ul><li><a href="/reference/tag-database">Tag Database</a> - Complete tag reference</li><li><a href="/reference/api-reference">API Reference</a> - Using formats in code</li><li><a href="/guide/cli-usage">CLI Usage</a> - Command-line examples</li><li><a href="https://exiftool.org/#supported" target="_blank" rel="noreferrer">ExifTool Format Support</a> - Original format list</li></ul>',133)])])}const u=e(r,[["render",s]]);export{c as __pageData,u as default};
